  uint64_t hi1 = (x.hi << n0) | (x.lo >> (64 - n0));
  uint64_t lo1 = (x.lo << n0) | (x.hi >> (64 - n0));
  uint64_t hi2 = (x.lo << n0) | (x.hi >> (64 - n0));
  uint64_t lo2 = (x.hi << n0) | (x.lo >> (64 - n0));
  uint128 r;
  r.hi = (hi1 & ~m) | (hi2 & m);
  r.lo = (lo1 & ~m) | (lo2 & m);
  return r;
}
```

