questions.answer:
Approach: Extract the four 32-bit lanes (A0, A1, A2, A3) using 32-bit masks and shifts, then reassemble them in reverse order. Specifically, NewHi = (A0 << 32) | A1 and NewLo = (A2 << 32) | A3. This is fully branchless, using only shifts, masks, and bitwise ORs.

Example: If x.lo = 0x0000000200000001 and x.hi = 0x0000000300000004, then A0=1, A1=2, A2=4, A3=3. This gives NewHi = (1<<32) | 2 = 0x0000000100000002 and NewLo = (4<<32) | 3 = 0x0000000400000003.

```javascript
function endiannessFlip128(x) {
  const MASK32 = 0xFFFFFFFFn;
  const A0 = x.lo & MASK32;
  const A1 = (x.lo >> 32n) & MASK32;
  const A2 = x.hi & MASK32;
  const A3 = (x.hi >> 32n) & MASK32;
  return { hi: (A0 << 32n) | A1, lo: (A2 << 32n) | A3 };
}

// Test 1: All zeros
console.log(endiannessFlip128({ hi: 0n, lo: 0n })); // { hi: 0n, lo: 0n }

// Test 2: Sequential pattern
console.log(endiannessFlip128({ hi: 0x0000000300000004n, lo: 0x0000000200000001n })); // { hi: 0x0000000100000002n, lo: 0x0000000400000003n }

