// outline of approach (conceptual; leverages 128-bit value split into bytes)
typedef struct { uint64_t hi; uint64_t lo; } uint128;
static inline uint128 perByteRotateLeft128(uint128 x, unsigned n){
    uint128 M = { 0xFFFFFFFFFFFFFFFFULL, 0xFFFFFFFFFFFFFFFFULL };
    uint128 left  = { .hi = (x.hi << n) | (x.lo >> (8 - n)), .lo = x.lo << n };
    uint128 right = { .hi = (x.hi >> (8 - n)), .lo = (x.lo >> (8 - n)) };
    return { .hi = (left.hi & M.hi) | (right.hi & ~M.hi),
