    uint64_t a0 = (uint32_t)a.lo;
    uint64_t a1 = (uint32_t)(a.lo >> 32);
    uint64_t a2 = (uint32_t)a.hi;
    uint64_t a3 = (uint32_t)(a.hi >> 32);

    uint64_t b0 = (uint32_t)b.lo;
    uint64_t b1 = (uint32_t)(b.lo >> 32);
    uint64_t b2 = (uint32_t)b.hi;
    uint64_t b3 = (uint32_t)(b.hi >> 32);

    uint64_t p0 = a0 ^ b0, g0 = a0 & b0;
    uint64_t p1 = a1 ^ b1, g1 = a1 & b1;
    uint64_t p2 = a2 ^ b2, g2 = a2 & b2;
    uint64_t p3 = a3 ^ b3, g3 = a3 & b3;

    uint64_t c1 = g0;
    uint64_t c2 = g0 | (p0 & g1);
    uint64_t c3 = g0 | (p0 & g1) | (p0 & p1 & g2);
    uint64_t c4 = g0 | (p0 & g1) | (p0 & p1 & g2) | (p0 & p1 & p2 & g3);

    uint128 r;
    r.lo = (p3 ^ c4) | ((p2 ^ c3) << 32) | ((p1 ^ c2) << 64) | ((p0 ^ c1) << 96);
    r.hi = (p3 ^ c4) >> 32;
    return r;
}
```

