  unsigned m0 = n0 & 31, m1 = n1 & 31, m2 = n2 & 31, m3 = n3 & 31;
  uint32_t w0 = (uint32_t)(x.lo);
  uint32_t w1 = (uint32_t)(x.lo >> 32);
