unsigned countTrailingZeros128(uint128 x) {
  static const unsigned char deBruijn64[64] = {
    0, 1, 2, 53, 3, 7, 54, 27,
    4, 38, 8, 34, 55, 48, 28, 20,
    5, 39, 53, 6, 59, 29, 42, 16,
    9, 35, 60, 50, 45, 27, 21, 17,
    10, 49, 56, 40, 30, 14, 43, 15,
    11, 23, 51, 52, 41, 19, 13, 44,
    12, 26, 58, 36, 31, 37, 29, 22
  };
  unsigned loIdx = ((x.lo & -x.lo) * 0x03f79d71b4cb0a89ull) >> 58;
  unsigned hiIdx = ((x.hi & -x.hi) * 0x03f79d71b4cb0a89ull) >> 58;
  unsigned tzLo = deBruijn64[loIdx];
  unsigned tzHi = deBruijn64[hiIdx];
  unsigned isLoZero = (x.lo == 0);
  return (1 - isLoZero) * tzLo + isLoZero * (64 + tzHi);
}
