## Code Example

```javascript
// C-like pseudocode
typedef struct { uint64_t hi; uint64_t lo; } uint128;
static inline uint128 shl1(uint128 x){
  uint128 r; r.hi = (x.hi << 1) | (x.lo >> 63); r.lo = x.lo << 1; return r; }
static inline unsigned popcount64(uint64_t x){
  x = x - ((x >> 1) & 0x5555555555555555ULL);
  x = (x & 0x3333333333333333ULL) + ((x >> 2) & 0x3333333333333333ULL);
  x = (x + (x >> 4)) & 0x0f0f0f0f0f0f0f0fULL;
  return (x * 0x0101010101010101ULL) >> 56; }
unsigned countRuns128(uint128 x){
  uint128 t = shl1(x);
  uint128 m; m.hi = x.hi & ~t.hi; m.lo = x.lo & ~t.lo;
  return popcount64(m.hi) + popcount64(m.lo);
}
```

