typedef struct { uint64_t hi; uint64_t lo; } uint128;

static inline int ctz64(uint64_t x) {
  if (x == 0) return 64;
  static const int tab[64] = { /* 64 entries */ };
  uint64_t y = x & -x;
  return tab[(y * 0x03f79d71b4cb0a89ULL) >> 58];
}

int lsbIndex128(uint128 x) {
  uint64_t lo = x.lo, hi = x.hi;
  int a = ctz64(lo);
  int b = 64 + ctz64(hi);
  int m = - (int)(lo != 0);
  int res = (a & m) | (b & ~m);
  return (lo | hi) == 0 ? -1 : res;
}
