Implement a 7-stage parallel popcount algorithm for 128-bit integers:

```javascript
uint128 countBits128(uint128 x) {
  const uint128 m1 = uint128(0x55555555555555555555555555555555);
  const uint128 m2 = uint128(0x33333333333333333333333333333333);
  const uint128 m4 = uint128(0x0F0F0F0F0F0F0F0F0F0F0F0F0F0F0F0F);

  // Stage 1: Extract and count bits in pairs (2 bits per position)
  x = x - ((x >> 1) & m1);

  // Stage 2: Accumulate pairs into 4-bit groups
  x = (x & m2) + ((x >> 2) & m2);

  // Stage 3: Accumulate nibbles into 8-bit groups
  x = (x + (x >> 4)) & m4;

  // Stage 4: Horizontal sum across all bytes (64-bit boundary)
  x = x + (x >> 8);
  x = x + (x >> 16);
  x = x + (x >> 32);
  x = x + (x >> 64);

  return x & 0x7F;
}
```

**Test cases:**
```javascript
assert(countBits128(0) === 0);
assert(countBits128(uint128(0xFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFF)) === 128);
```

