**Solution using SWAR deinterleaving:**

```c
typedef struct { uint64_t hi; uint64_t lo; } uint128;

uint64_t packOddBits128(uint128 x) {
    const uint64_t MASK = 0xAAAAAAAAAAAAAAAAULL;
    uint64_t lo = (x.lo & MASK) >> 1;
    uint64_t hi = (x.hi & MASK) >> 1;
    return lo | (hi << 32);
}
```

**Justification:** The mask `0xAA...` (binary `1010...`) isolates odd-indexed bits. We apply it separately to the high and low 64-bit halves, shift right by 1 to compress them into contiguous positions, then combine—placing the high half's odd bits in the upper 32 bits of the result.

**Tests:**
```c
/* All bits set in lo half only */
uint128 a = { .lo = 0xFFFFFFFFFFFFFFFFULL, .hi = 0 };
assert(packOddBits128(a) == 0x5555555555555555ULL);

/* All odd bits set across both halves */
uint128 b = { .lo = 0xFFFFFFFFFFFFFFFFULL, .hi = 0xFFFFFFFFFFFFFFFFULL };
assert(packOddBits128(b) == 0xFFFFFFFFFFFFFFFFULL);
```

Compute x = a ^ b to identify differing bit positions, then apply popcount via SWAR (SIMD Within A Register) on each 64-bit half independently. For a single 64-bit word:

```c
unsigned hammingDistance128(uint128 a, uint128 b) {
    uint64_t lo = a.lo ^ b.lo;
    uint64_t hi = a.hi ^ b.hi;

    lo = lo - ((lo >> 1) & 0x5555555555555555ULL);
    lo = (lo & 0x3333333333333333ULL) + ((lo >> 2) & 0x3333333333333333ULL);
    lo = (lo + (lo >> 4)) & 0x0F0F0F0F0F0F0F0FULL;
    lo = (lo * 0x0101010101010101ULL) >> 56;

    hi = hi - ((hi >> 1) & 0x5555555555555555ULL);
    hi = (hi & 0x3333333333333333ULL) + ((hi >> 2) & 0x3333333333333333ULL);
    hi = (hi + (hi >> 4)) & 0x0F0F0F0F0F0F0F0FULL;
    hi = (hi * 0x0101010101010101ULL) >> 56;

    return (unsigned)(lo + hi);
}
```

Justification: XOR isolates differing bits; SWAR popcount computes the count in O(1) using parallel addition and masking—no branches or loops.

Tests:
```c
hammingDistance128((uint128){0, 0}, (uint128){0, 0}) == 0;                                        // identical values
hammingDistance128((uint128){1, 1}, (uint128){0, 0}) == 2;                                        // differ in LSB of each half
hammingDistance128((uint128){0, 0xFFFFFFFFFFFFFFFFULL}, (uint128){0xFFFFFFFFFFFFFFFFULL, 0}) == 128; // all bits differ
```

