void rotate_left_128(uint64_t hi, uint64_t lo, unsigned k, 
                    uint64_t* out_hi, uint64_t* out_lo) {
    uint64_t t = k & 63;
    uint64_t b = (k >> 6) & 1;

    uint64_t hiA = (hi << t) | (lo >> (64 - t));
    uint64_t loA = (lo << t) | (hi >> (64 - t));
    uint64_t hiB = (lo << t) | (hi >> (64 - t));
    uint64_t loB = (hi << t) | (lo >> (64 - t));

    *out_hi = hiA ^ ((hiA ^ hiB) & -b);
    *out_lo = loA ^ ((loA ^ loB) & -b);
}
```

