typedef struct { uint64_t hi, lo; } uint128_t;
static inline uint128_t rotl128(uint128_t x, unsigned k){
  k %= 128; uint128_t r;
  if (k < 64){
    r.hi = (x.hi << k) | (x.lo >> (64 - k));
    r.lo = (x.lo << k) | (x.hi >> (64 - k));
  } else { unsigned kk = k - 64;
    r.hi = (x.lo << kk) | (x.hi >> (64 - kk));
    r.lo = (x.hi << kk) | (x.lo >> (64 - kk));
  }
  return r;
}
